import {useEffect,useState} from "react";
import API from "../services/api";

export default function AdminDashboard(){
  const [data,setData]=useState([]);

  useEffect(()=>{
    API.get("/biodata/admin").then(res=>setData(res.data));
  },[]);

  return (
    <div style={{padding:20}}>
      <h2>Admin</h2>
      {data.map(d=>(
        <div key={d._id}>
          {d.fullName} - {d.email}
        </div>
      ))}
    </div>
  );
}
